import { Link } from 'react-router-dom'

import { FitnessCenter, FolderOpen as FolderOpenIcon } from '@mui/icons-material'
import { Button } from '@mui/material'
import type { ButtonProps } from '@mui/material'

import { routes } from '@/routes'
import type { TrainingPlan } from '@/types/database'

function parseFmUrl(unitName: string): { owner: string; repo: string; path?: string } | null {
  if (!unitName.startsWith('fm://')) return null
  const parts = unitName.replace('fm://', '').split('/')
  if (parts.length < 2) return null
  return {
    owner: parts[0],
    repo: parts[1],
    path: parts.length > 2 ? parts.slice(2).join('/') : undefined,
  }
}

interface PlanExecutionButtonProps {
  plan: TrainingPlan
  size?: ButtonProps['size']
  variant?: ButtonProps['variant']
}

export function PlanExecutionButton({ plan, size, variant }: PlanExecutionButtonProps) {
  const fmInfo = parseFmUrl(plan.unit_name)

  if (fmInfo) {
    return (
      <Button
        component={Link}
        to={routes.flashMan.contents.$({
          owner: fmInfo.owner,
          repo: fmInfo.repo,
          path: fmInfo.path,
        })}
        startIcon={<FolderOpenIcon />}
        size={size}
        variant={variant}
      >
        폴더이동
      </Button>
    )
  }

  return (
    <Button
      component={Link}
      to={routes.executions.new.$({ planId: plan.id })}
      startIcon={<FitnessCenter />}
      size={size}
      variant={variant}
    >
      훈련시작
    </Button>
  )
}
